{
  "title": "Warteschlangen-Operationen",
  "group": "Datenstrukturen",
  "options": [
    {
      "text": "Enqueue und Dequeue",
      "hint": "Füge ein Element am Ende hinzu und entferne vom Anfang"
    },
    {
      "text": "Push und Pop",
      "hint": "Wird für Stapel verwendet, nicht für Warteschlangen"
    },
    {
      "text": "Peek und Top",
      "hint": "Zeigt das erste Element an, ohne es zu entfernen"
    },
    {
      "text": "Traverse und Sort",
      "hint": "Nicht primäre Warteschlangenoperationen"
    }
  ],
  "questionProse": [
    "Welche sind die beiden primären Operationen für eine Warteschlange?"
  ],
  "explanationProse": [
    "Die beiden primären Operationen in einer Warteschlange sind Enqueue (Element am Ende hinzufügen) und Dequeue (Element vom Anfang entfernen)."
  ]
}
